CREATE TABLE `Course` (
  `course_id` int NOT NULL AUTO_INCREMENT,
  `university_id` int NOT NULL,
  `program_id` int DEFAULT NULL,
  `lesson_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `language` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `website` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `semester_number` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `semester_label` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `ects_list` json DEFAULT NULL,
  `mand_opt_list` json DEFAULT NULL,
  `msc_bsc_list` json DEFAULT NULL,
  `fee_list` json DEFAULT NULL,
  `hours` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `description` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `objectives` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `learning_outcomes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `course_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `assessment` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `exam` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `prerequisites` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `general_competences` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `educational_material` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `attendance_type` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `professors` json DEFAULT NULL,
  `extras` json DEFAULT NULL,
  `degree_titles` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`course_id`),
  KEY `idx_course_univ` (`university_id`),
  KEY `idx_course_program` (`program_id`),
  KEY `idx_course_name` (`lesson_name`),
  FULLTEXT KEY `ft_course_text` (`description`,`objectives`,`learning_outcomes`,`course_content`),
  CONSTRAINT `fk_course_program` FOREIGN KEY (`program_id`) REFERENCES `DegreeProgram` (`program_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_course_univ` FOREIGN KEY (`university_id`) REFERENCES `University` (`university_id`) ON DELETE CASCADE,
  CONSTRAINT `Course_chk_1` CHECK (((`ects_list` is null) or json_valid(`ects_list`))),
  CONSTRAINT `Course_chk_2` CHECK (((`mand_opt_list` is null) or json_valid(`mand_opt_list`))),
  CONSTRAINT `Course_chk_3` CHECK (((`msc_bsc_list` is null) or json_valid(`msc_bsc_list`))),
  CONSTRAINT `Course_chk_4` CHECK (((`fee_list` is null) or json_valid(`fee_list`))),
  CONSTRAINT `Course_chk_5` CHECK (((`professors` is null) or json_valid(`professors`))),
  CONSTRAINT `Course_chk_6` CHECK (((`extras` is null) or json_valid(`extras`))),
  CONSTRAINT `Course_chk_7` CHECK (((`degree_titles` is null) or json_valid(`degree_titles`)))
) ENGINE=InnoDB AUTO_INCREMENT=383 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
